import React, { useState } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";


function Register(){
    const navigate=useNavigate();
    const [name,setName]=useState("");
    const [username,setUsername]=useState("");
    const [password,setPassword]=useState("");

    const handleSubmit=async ()=>{
        const response=await fetch('http://localhost:5000/register',{
            method:'POST',
            headers:{'Content-Type':'application/json'},
            body:JSON.stringify(name,username,password)
        });
        const data=await response.json();
        console.log(data);
    }

    function goToDashboard() {
                navigate('/dashboard');
    }

    return(
        <>
            <h1>Register Here</h1>
            <div className="signcontainer">
                <br/><form onSubmit={handleSubmit}>
                    <label htmlFor="name">Name:</label><br/>
                    <input type="text" name="name" id="name" onChange={()=>setName(e.target.value)}/><br/><br/>
                    <label htmlFor="username">Username:</label><br/>
                    <input type="text" name="name" id="username" onChange={()=>setUsername(e.target.value)}/><br/><br/>
                    <label htmlFor="password">Password:</label><br/>
                    <input type="text" name="password" id="password" onChange={()=>setPassword(e.target.value)}/><br/><br/>
                
                <button type="submit" onClick={goToDashboard}>Register</button>
                </form>
            </div>
    
        </>
    );
}

export default Register;
